    string brand;
    int price;
public:
    Car(string s1, string s2) : color(s1), brand(s2), price(50000) {}
    Car(string s1, string s2, int n) : color(s1), brand(s2), price(n) {}
    void show_color() {
        cout << color << endl;
    }
};

int main() {
    Car mazda("black", "Mazda");
    Car toyota("white", "Toyota", 1000000);
    mazda.show_color();
    toyota.show_color();
    return 0;
}
```

**輸出**：
```
black
white
```

