**練習：傳遞物件陣列**：
```cpp
#include <iostream>
using namespace std;

class CWin {
public:
    char id;
    int width, height;
    CWin(char i = 'D', int w = 100, int h = 100) : id(i), width(w), height(h) {}
};

void print_area(CWin win_arr[], int n) {
    for (int i = 0; i < n; i++) {
        cout << "window " << win_arr[i].id << ": " << win_arr[i].width * win_arr[i].height << endl;
    }
}

int main() {
